#requires -Version 5.1
<# Created by Dewald Pretorius. Read-only certificate security posture validator. #>
[CmdletBinding()]param([ValidateRange(1,3650)][int]$ExpiryWarningDays=30,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'Certificate_Posture_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{$now=Get-Date;$certs=@(Get-ChildItem Cert:\LocalMachine\My,Cert:\LocalMachine\WebHosting,Cert:\CurrentUser\My -ErrorAction SilentlyContinue|ForEach-Object{$days=[math]::Floor(($_.NotAfter-$now).TotalDays);$weak=($_.SignatureAlgorithm.FriendlyName-match'SHA1|MD5');[pscustomobject]@{Subject=$_.Subject;Issuer=$_.Issuer;Thumbprint=$_.Thumbprint;NotAfter=$_.NotAfter;DaysRemaining=$days;SignatureAlgorithm=$_.SignatureAlgorithm.FriendlyName;HasPrivateKey=$_.HasPrivateKey;Expired=($days-lt0);ExpiringSoon=($days-ge0-and$days-le$ExpiryWarningDays);WeakSignature=$weak}});$findings=@($certs|Where-Object{$_.Expired-or$_.ExpiringSoon-or$_.WeakSignature});$certs|Export-Csv (Join-Path $OutputPath "certificates_$s.csv") -NoTypeInformation;[ordered]@{Generated=(Get-Date);FindingCount=$findings.Count;Findings=$findings}|ConvertTo-Json -Depth 6|Set-Content (Join-Path $OutputPath "certificate_posture_$s.json");if($findings.Count){exit 1};exit 0}catch{Write-Error $_;exit 5}
